import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

public class PathTraversalFixed {

    public static void main(String[] args) throws IOException {
        System.out.print("Enter file name: ");
        String fileName = new Scanner(System.in).nextLine();

        Path filePath = Paths.get("C:/data/", fileName).toAbsolutePath().normalize();

        if (filePath.startsWith(Paths.get("C:/data/")) && Files.exists(filePath) && Files.isRegularFile(filePath)) {
            Files.lines(filePath).forEach(System.out::println);
        } else {
            System.out.println("File not found or invalid path!");
        }
    }
}

### Explanation:
취약유형: Path Traversal
